#include <stdio.h>
#include <stdlib.h>

int cmp_int(const void *a, const void *b) {
    int x = *(const int *)a;
    int y = *(const int *)b;
    return x - y;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, X; scanf("%d %d", &N, &X);
        int *deficits = (int *)malloc(N * sizeof(int));
        int defCnt = 0;
        long long surplus = 0;
        int good = 0;
        for (int i = 0; i < N; ++i) {
            int a; scanf("%d", &a);
            if (a >= X) {
                good++;
                if (a > X) surplus += (long long)(a - X);
            } else {
                deficits[defCnt++] = X - a;
            }
        }
        qsort(deficits, defCnt, sizeof(int), cmp_int);
        long long used = 0;
        int satisfied = 0;
        for (int i = 0; i < defCnt; ++i) {
            if (used + deficits[i] <= surplus) {
                used += deficits[i];
                satisfied++;
            } else break;
        }
        printf("%d\n", good + satisfied);
        free(deficits);
    }
    return 0;
}

