import sys

def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it); X = next(it)
        good = 0
        surplus = 0
        deficits = []
        for _ in range(N):
            a = next(it)
            if a >= X:
                good += 1
                if a > X:
                    surplus += a - X
            else:
                deficits.append(X - a)
        deficits.sort()
        used = 0
        satisfied = 0
        for d in deficits:
            if used + d <= surplus:
                used += d
                satisfied += 1
            else:
                break
        out_lines.append(str(good + satisfied))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

